// src/components/MobileMenu.jsx
import React, { useEffect } from 'react';
import { X, Menu } from 'lucide-react';

const MobileMenu = ({
    isOpen,
    onToggle,
    onClose,
    children,
    position = 'right',
    width = '300px',
    overlay = true,
    closeOnRouteChange = true,
    className = ''
}) => {

    // Fermer le menu quand la route change
    useEffect(() => {
        if (closeOnRouteChange) {
            onClose();
        }
    }, [window.location.pathname, closeOnRouteChange, onClose]);

    // Empêcher le scroll du body quand le menu est ouvert
    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = 'unset';
        }

        return () => {
            document.body.style.overflow = 'unset';
        };
    }, [isOpen]);

    return (
        <>
            {/* Bouton menu burger */}
            <button
                className="btn btn-link p-0 border-0 d-lg-none"
                onClick={onToggle}
                aria-label="Menu"
                style={{ color: 'inherit', textDecoration: 'none' }}
            >
                {isOpen ? <X size={24} /> : <Menu size={24} />}
            </button>

            {/* Overlay */}
            {overlay && isOpen && (
                <div
                    className="mobile-overlay"
                    onClick={onClose}
                    style={{
                        position: 'fixed',
                        top: 0,
                        left: 0,
                        right: 0,
                        bottom: 0,
                        backgroundColor: 'rgba(0, 0, 0, 0.5)',
                        zIndex: 1040,
                        animation: 'fadeIn 0.3s ease'
                    }}
                />
            )}

            {/* Menu mobile */}
            <div
                className={`mobile-menu ${className}`}
                style={{
                    position: 'fixed',
                    top: 0,
                    [position]: isOpen ? 0 : `-${width}`,
                    width: width,
                    height: '100vh',
                    backgroundColor: 'white',
                    boxShadow: '0 0 20px rgba(0,0,0,0.1)',
                    transition: `${position} 0.3s ease`,
                    zIndex: 1050,
                    overflowY: 'auto',
                    padding: '20px'
                }}
            >
                {/* En-tête du menu mobile */}
                <div className="mobile-menu-header d-flex justify-content-between align-items-center mb-4 pb-3 border-bottom">
                    <h5 className="mb-0 fw-bold">Menu</h5>
                    <button
                        className="btn btn-link p-0"
                        onClick={onClose}
                        aria-label="Fermer"
                    >
                        <X size={24} />
                    </button>
                </div>

                {/* Contenu du menu */}
                <div className="mobile-menu-content">
                    {children}
                </div>
            </div>

            {/* Styles globaux */}
            <style jsx global>{`
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }

        @keyframes slideIn {
          from {
            transform: translateX(var(--slide-from));
          }
          to {
            transform: translateX(0);
          }
        }

        /* Ajustements responsifs */
        @media (max-width: 576px) {
          .mobile-menu {
            width: 85% !important;
          }
        }

        /* Classe utilitaire pour cacher sur desktop */
        .d-lg-none {
          display: block;
        }
        @media (min-width: 992px) {
          .d-lg-none {
            display: none !important;
          }
        }
      `}</style>
        </>
    );
};

export default MobileMenu;
